local http = require "resty.http"

local function proxy_request()
    local url = ngx.var.arg_url
    local httpc = http.new()
    local res, err = httpc:request_uri(url)
    if not res then
        ngx.status = 500
        ngx.say("Failed to fetch content from URL: " .. url)
        return
    end
    ngx.say(res.body)
end